('ph-foundations', NULL, 1, 'phase', NULL, NULL, NULL, 'Cybersecurity Foundations', 'Understand the cybersecurity role, threat landscape, ethics, risk, legal boundaries, and the core security mindset.', 'Major roadmap phase for cybersecurity foundations.', 'trunk', 'ph-foundations', 1, 0, 22, 'beginner', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Cybersecurity Foundations.","Apply Cybersecurity Foundations in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Cybersecurity Foundations.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-networking', NULL, 2, 'phase', NULL, NULL, NULL, 'Networking and Internet Security', 'Build networking depth: TCP/IP, DNS, routing, firewalls, VPNs, packet analysis, and network threat models.', 'Major roadmap phase for networking and internet security.', 'trunk', 'ph-networking', 2, 0, 36, 'beginner', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Networking and Internet Security.","Apply Networking and Internet Security in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Networking and Internet Security.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-linux-windows', NULL, 3, 'phase', NULL, NULL, NULL, 'Operating Systems, Linux, and Windows Security', 'Learn how systems work, how to administer them, and how attackers and defenders interact with endpoints.', 'Major roadmap phase for operating systems, linux, and windows security.', 'trunk', 'ph-linux-windows', 3, 0, 38, 'beginner', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Operating Systems, Linux, and Windows Security.","Apply Operating Systems, Linux, and Windows Security in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Operating Systems, Linux, and Windows Security.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-programming', NULL, 4, 'phase', NULL, NULL, NULL, 'Programming, Scripting, and Automation', 'Use Python, Bash, PowerShell, APIs, and Git to automate security tasks and build tools safely.', 'Major roadmap phase for programming, scripting, and automation.', 'trunk', 'ph-programming', 4, 0, 34, 'beginner', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Programming, Scripting, and Automation.","Apply Programming, Scripting, and Automation in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Programming, Scripting, and Automation.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-web-appsec', NULL, 5, 'phase', NULL, NULL, NULL, 'Web, API, and Application Security', 'Learn web architecture, OWASP risks, secure coding, API security, authentication, and web security testing.', 'Major roadmap phase for web, api, and application security.', 'trunk', 'ph-web-appsec', 5, 0, 48, 'intermediate', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Web, API, and Application Security.","Apply Web, API, and Application Security in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Web, API, and Application Security.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-crypto-iam', NULL, 6, 'phase', NULL, NULL, NULL, 'Cryptography, Identity, and Access Management', 'Understand applied crypto, passwords, MFA, OAuth/OIDC, PKI, secrets, and enterprise identity security.', 'Major roadmap phase for cryptography, identity, and access management.', 'trunk', 'ph-crypto-iam', 6, 0, 36, 'intermediate', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Cryptography, Identity, and Access Management.","Apply Cryptography, Identity, and Access Management in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Cryptography, Identity, and Access Management.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-blue-team', NULL, 7, 'phase', NULL, NULL, NULL, 'SOC, Detection Engineering, and Threat Intelligence', 'Practice alert triage, SIEM, logs, detections, ATT&CK mapping, threat intel, and blue-team workflows.', 'Major roadmap phase for soc, detection engineering, and threat intelligence.', 'trunk', 'ph-blue-team', 7, 0, 52, 'intermediate', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain SOC, Detection Engineering, and Threat Intelligence.","Apply SOC, Detection Engineering, and Threat Intelligence in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of SOC, Detection Engineering, and Threat Intelligence.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-dfir', NULL, 8, 'phase', NULL, NULL, NULL, 'Incident Response and Digital Forensics', 'Learn incident handling, evidence collection, timeline analysis, memory, disk, endpoint, and cloud forensics.', 'Major roadmap phase for incident response and digital forensics.', 'trunk', 'ph-dfir', 8, 0, 44, 'intermediate', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Incident Response and Digital Forensics.","Apply Incident Response and Digital Forensics in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Incident Response and Digital Forensics.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-offensive', NULL, 9, 'phase', NULL, NULL, NULL, 'Ethical Hacking and Penetration Testing', 'Learn authorized recon, enumeration, vulnerability validation, exploit understanding, reporting, and remediation guidance.', 'Major roadmap phase for ethical hacking and penetration testing.', 'trunk', 'ph-offensive', 9, 0, 54, 'advanced', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Ethical Hacking and Penetration Testing.","Apply Ethical Hacking and Penetration Testing in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Ethical Hacking and Penetration Testing.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-cloud-devsecops', NULL, 10, 'phase', NULL, NULL, NULL, 'Cloud, Container, and DevSecOps Security', 'Secure AWS/Azure/GCP, containers, Kubernetes, CI/CD, IaC, secrets, and runtime environments.', 'Major roadmap phase for cloud, container, and devsecops security.', 'trunk', 'ph-cloud-devsecops', 10, 0, 48, 'advanced', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Cloud, Container, and DevSecOps Security.","Apply Cloud, Container, and DevSecOps Security in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Cloud, Container, and DevSecOps Security.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-governance', NULL, 11, 'phase', NULL, NULL, NULL, 'Governance, Risk, Compliance, and Privacy', 'Understand security programs, controls, risk management, policies, audits, privacy, and compliance frameworks.', 'Major roadmap phase for governance, risk, compliance, and privacy.', 'trunk', 'ph-governance', 11, 0, 32, 'intermediate', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Governance, Risk, Compliance, and Privacy.","Apply Governance, Risk, Compliance, and Privacy in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Governance, Risk, Compliance, and Privacy.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-specializations', NULL, 12, 'phase', NULL, NULL, NULL, 'Advanced Specializations', 'Explore malware analysis, reverse engineering, exploit development concepts, OT/ICS, IoT, and security architecture.', 'Major roadmap phase for advanced specializations.', 'trunk', 'ph-specializations', 12, 0, 44, 'advanced', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Advanced Specializations.","Apply Advanced Specializations in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Advanced Specializations.","Document evidence, tradeoffs, and next steps."]'::jsonb),
('ph-career-capstone', NULL, 13, 'phase', NULL, NULL, NULL, 'Portfolio, Certification, and Capstone', 'Package evidence, write reports, prepare for interviews/certifications, and complete a defensive/offensive capstone.', 'Major roadmap phase for portfolio, certification, and capstone.', 'trunk', 'ph-career-capstone', 13, 0, 34, 'intermediate', 100, NULL, NULL, '{"source":"roadmap.sh/cyber-security","visualRole":"trunk"}'::jsonb, true, false, '["Explain Portfolio, Certification, and Capstone.","Apply Portfolio, Certification, and Capstone in a safe, authorized security context."]'::jsonb, '["Demonstrate practical understanding of Portfolio, Certification, and Capstone.","Document evidence, tradeoffs, and next steps."]'::jsonb),
